mapper.select:
SELECT o.order_id, o.order_no, o.business_id, o.bid_id, o.total_amount, o.payment_status, o.delivery_status, o.accept_status, o.due_date, o.created_at, o.customer_id, c.nickname AS customer_nickname, cr.room_id FROM orders o JOIN customer c ON c.customer_id = o.customer_id LEFT JOIN chat_room cr ON cr.bid_id = o.bid_id AND cr.business_id = o.business_id AND cr.customer_id = o.customer_id WHERE o.business_id = #{businessId} AND o.payment_status = 'PAID' AND o.accept_status = 'ACCEPTED' AND o.bid_id IS NOT NULL
AND ( c.nickname LIKE CONCAT('%', #{search.keyword}, '%') OR o.order_no LIKE CONCAT('%', #{search.keyword}, '%') OR EXISTS ( SELECT 1 FROM bids b JOIN request r ON r.request_id = b.request_id WHERE b.bid_id = o.bid_id AND r.title LIKE CONCAT('%', #{search.keyword}, '%') ) )
AND o.created_at >= #{search.startDate}
AND o.created_at < DATE_ADD(#{search.endDate}, INTERVAL 1 DAY)
ORDER BY o.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT o.order_id, o.order_no, o.business_id, o.bid_id, o.total_amount, o.payment_status, o.delivery_status, o.accept_status, o.due_date, o.created_at, o.customer_id, c.nickname AS customer_nickname, cr.room_id FROM orders o JOIN customer c ON c.customer_id = o.customer_id LEFT JOIN chat_room cr ON cr.bid_id = o.bid_id AND cr.business_id = o.business_id AND cr.customer_id = o.customer_id WHERE o.payment_status = 'PAID' AND o.bid_id IS NOT NULL
AND ( c.nickname LIKE CONCAT('%', #{search.keyword}, '%') OR o.order_no LIKE CONCAT('%', #{search.keyword}, '%') OR EXISTS ( SELECT 1 FROM bids b JOIN request r ON r.request_id = b.request_id WHERE b.bid_id = o.bid_id AND r.title LIKE CONCAT('%', #{search.keyword}, '%') ) )
AND o.created_at >= #{search.startDate}
AND o.created_at < DATE_ADD(#{search.endDate}, INTERVAL 1 DAY)
ORDER BY o.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT room_id
FROM chat_room
WHERE bid_id      = #{bidId}
  AND customer_id = #{customerId}
  AND business_id = #{businessId}
LIMIT 1
